import React, { useState, useEffect } from "react";
import { Button, Container, Row, Col, Card, Alert, Spinner } from "react-bootstrap";
import { useNavigate, useParams } from "react-router-dom";
import { createOrder } from "../services/orderService";  // Đảm bảo đã import dịch vụ orderService

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [ticketQuantity, setTicketQuantity] = useState(0); // Giữ số lượng vé
  const [walletAddress, setWalletAddress] = useState(null);

  useEffect(() => {
    // Kiểm tra ví đã liên kết
    const storedWallet = localStorage.getItem("wallet_address");
    if (!storedWallet) {
      setError("Bạn cần liên kết ví trước khi đặt vé");
    } else {
      setWalletAddress(storedWallet);
    }

    // Lấy chi tiết sự kiện và ticket types
    const fetchEventAndTickets = async () => {
      try {
        setLoading(true);
        const response = await api.get(`/users/events/${id}`);  // Sử dụng API để lấy chi tiết sự kiện
        setEvent(response.data.data); // Lưu event vào state
      } catch (err) {
        setError("Lỗi khi tải chi tiết sự kiện");
      } finally {
        setLoading(false);
      }
    };

    fetchEventAndTickets();
  }, [id]);

  // Xử lý sự kiện khi người dùng thay đổi số lượng vé
  const handleQuantityChange = (event) => {
    setTicketQuantity(event.target.value);
  };

  // Xử lý khi tạo đơn hàng
  const handleCreateOrder = async () => {
    if (!walletAddress) {
      setError("Bạn cần liên kết ví trước khi đặt vé");
      return;
    }

    if (ticketQuantity <= 0) {
      setError("Số lượng vé phải lớn hơn 0");
      return;
    }

    try {
      const items = [
        {
          ticket_type_id: event.ticket_types[0].id,  // Giả sử lấy ticket type đầu tiên
          quantity: ticketQuantity,
        },
      ];

      const orderResponse = await createOrder({ items, walletAddress });
      if (orderResponse.success) {
        navigate("/payment");  // Chuyển đến trang thanh toán
      }
    } catch (err) {
      setError("Đã có lỗi khi tạo đơn hàng");
    }
  };

  // Hiển thị loading spinner khi đang tải
  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ height: "100vh" }}>
        <Spinner animation="border" variant="primary" />
      </div>
    );
  }

  // Nếu có lỗi khi tải
  if (error) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );
  }

  // Nếu không tìm thấy sự kiện
  if (!event) {
    return (
      <Container className="text-center mt-5">
        <Alert variant="warning">Không tìm thấy sự kiện này.</Alert>
      </Container>
    );
  }

  return (
    <Container className="my-5">
      <Row>
        <Col md={8}>
          <Card>
            <Card.Img
              variant="top"
              src={event.banner_image ? `/images/${event.banner_image}` : "/images/default-banner.jpg"}
              alt={event.title}
            />
            <Card.Body>
              <Card.Title>{event.title}</Card.Title>
              <Card.Text>{event.description}</Card.Text>
              <Card.Text><strong>Địa điểm:</strong> {event.location}</Card.Text>
              <Card.Text><strong>Ngày sự kiện:</strong> {new Date(event.event_date).toLocaleDateString("vi-VN")}</Card.Text>
              <Button variant="primary" onClick={handleCreateOrder}>Mua vé ngay</Button>
            </Card.Body>
          </Card>
        </Col>
        <Col md={4}>
          <Card>
            <Card.Body>
              <Card.Title>Thông tin sự kiện</Card.Title>
              <Card.Text><strong>Người tổ chức:</strong> {event.organizer_name}</Card.Text>
              <Card.Text><strong>Trạng thái:</strong> {event.status}</Card.Text>
              <Card.Text><strong>Số lượng vé:</strong> {event.ticket_types[0]?.quantity_total || 0}</Card.Text>
              <Card.Text><strong>Số lượng còn lại:</strong> {event.ticket_types[0]?.quantity_available || 0}</Card.Text>
              <Card.Text><strong>Giới hạn mỗi đơn:</strong> {event.ticket_types[0]?.max_per_order || 0}</Card.Text>
              <Card.Text><strong>Giá vé:</strong> {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(event.ticket_types[0]?.price)}</Card.Text>
              <input
                type="number"
                min="1"
                max={event.ticket_types[0]?.quantity_available || 0}
                value={ticketQuantity}
                onChange={handleQuantityChange}
                placeholder="Chọn số lượng"
              />
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
